    notes: arch.notes || null
  },
  stored_response: storedResponseContent
}}];

// Map RPC application errors to HTTP envelope. Carries forward Validate Input for request_id.
const inp = $('Validate Input').first().json;
const result = $json && $json.result;
function rpcErr(http, code, msg, details) { return [{ json: { __rpc_error: { error: code, message: msg, details: details || null, request_id: inp.request_id, http_status: http } } }]; }
if (!result) return rpcErr(503, 'internal_error', 'create_architecture_revision returned no result', null);
if (result.error) {
  const map = {
    invalid_action: 400, invalid_status: 400,
    idempotency_key_required: 400, invalid_payload_hash: 400, stored_response_required: 400,
    components_not_array: 400, tasks_not_array: 400, build_order_not_array: 400, dependencies_not_object: 400,
    project_id_required: 400, spec_id_required: 400,
    spec_not_found: 404, spec_project_mismatch: 409,
    spec_not_reviewable: 422,
    task_not_found: 404, task_project_mismatch: 409,
    idempotency_conflict: 409,
    architecture_exists: 422, architecture_not_found: 404,
    concurrent_active_revision: 409, version_race: 409, unique_violation: 409
  };
  return rpcErr(map[result.error] || 500, result.error, result.detail || 'rpc error', { rpc_detail: result.detail || null });
}
return [{ json: { rpc_ok: true, result } }];

// RPC reported replayed=true (lost a concurrent race). stored_response intentionally
// excludes version/status (RPC-assigned fields), so we reloaded the row by architecture_id
// to obtain authoritative version + status. Closes codex AGEN-ARCH-SHIP-002.
const inp = $('Validate Input').first().json;
const rpc = $('Check RPC Result').first().json.result;
const stored = rpc.response || {};
const reloaded = ($json && $json.row) ? $json.row : null;
if (!reloaded || typeof reloaded.version !== 'number' || !reloaded.status) {
  return [{ json: { __error: { error: 'internal_error', message: 'replayed architecture row could not be reloaded for authoritative version/status', details: { architecture_id: rpc.architecture_id }, request_id: inp.request_id, http_status: 500 } } }];
}
return [{ json: {
  architecture_id: rpc.architecture_id,
  spec_id: inp.spec_id,
  project_id: inp.project_id,
  status: reloaded.status,
  version: reloaded.version,
  components: stored.components || [],
  tasks: stored.tasks || [],
  build_order: stored.build_order || [],
  dependencies: stored.dependencies || {},
  replayed: true,
  request_id: inp.request_id
} }];

// Fresh-insert response — pulls the persisted architecture row from the RPC result.
const inp = $('Validate Input').first().json;
const parsed = $('Parse + Validate Architecture').first().json.parsed;
const row = $('Create Architecture Revision').first().json.result.architecture;
return [{ json: {
  architecture_id: row.id,
  spec_id: inp.spec_id,
  project_id: inp.project_id,
  status: row.status,
  version: row.version,
  components: row.components || parsed.components,
  tasks: row.tasks || parsed.tasks,
  build_order: row.build_order || parsed.build_order,
  dependencies: row.dependencies || parsed.dependencies,
  replayed: false,
  request_id: inp.request_id
} }];

const inp = $('Validate Input').first().json;
const row = $json && $json.architecture;
if (!row) {
  return [{ json: { __error: { error: 'architecture_not_found', message: 'no architecture exists for (project_id, spec_id)', details: { project_id: inp.project_id, spec_id: inp.spec_id }, request_id: inp.request_id, http_status: 404 } } }];
}
return [{ json: {
  architecture_id: row.id,
  spec_id: row.spec_id,
  project_id: row.project_id,
  status: row.status,
  version: row.version,
  components: row.components || [],
  tasks: row.tasks || [],
  build_order: row.build_order || [],
  dependencies: row.dependencies || {},
  replayed: false,
  request_id: inp.request_id
} }];
